// プリミティブ型: 値のコピーが渡される
// changeValueメソッドの定義
static void changeValue(int x) {
    x = 100; // コピーを変更しても元に影響なし
}
// 変数の宣言と初期化
int num = 10;
changeValue(num);
System.out.println(num); // 10（変わらない）

// 参照型（配列）: 参照のコピーが渡される
// changeArrayメソッドの定義
static void changeArray(int[] arr) {
    arr[0] = 999; // 同じ配列を操作→反映される
}
int[] data = {1, 2, 3};
changeArray(data);
System.out.println(data[0]); // 999（変わる！）

// ただし参照自体の再代入は反映されない
static void replaceArray(int[] arr) {
    arr = new int[]{10, 20, 30}; // 参照のコピーを差し替えただけ
}
int[] original = {1, 2, 3};
replaceArray(original);
System.out.println(original[0]); // 1（変わらない！）

// パターン1: 配列で返す
static int[] minMax(int[] nums) {
    // 変数の宣言と初期化
    int min = Integer.MAX_VALUE;
    int max = Integer.MIN_VALUE;
    // 繰り返し処理（for文）
    for (int i = 0; i < nums.length; i++) {
        // 条件分岐
        if (nums[i] < min) min = nums[i];
        if (nums[i] > max) max = nums[i];
    }
    return new int[]{min, max};
}
int[] result = minMax(new int[]{5, 2, 8, 1});
System.out.println("最小: " + result[0] + ", 最大: " + result[1]);

