// 可変長引数: 型... 変数名
static int sum(int... numbers) {
    int total = 0;
    for (int n : numbers) {
        total += n;
    }
    return total;
}

// 引数の数を自由に変えられる
System.out.println(sum());          // 0
System.out.println(sum(1, 2));      // 3
System.out.println(sum(1, 2, 3, 4)); // 10

// 配列を渡すことも可能
int[] data = {10, 20, 30};
System.out.println(sum(data)); // 60

// ルール:
// 1. 可変長引数はメソッドの最後の引数のみ
// 2. 1つのメソッドに可変長引数は1つだけ

// OK: 通常引数 + 可変長引数
static String format(String prefix, String... items) {
    return prefix + ": " + String.join(", ", items);
}
System.out.println(format("果物", "りんご", "みかん"));
// → 果物: りんご, みかん

// NG: 可変長引数が最後でない
// static void bad(int... a, String b) {} // コンパイルエラー！

public class Calculator {
    private int memory = 0; // インスタンス変数

    // staticメソッド: クラスに属する
    // → オブジェクトを作らず呼べる
    // → インスタンス変数にアクセスできない
    static int add(int a, int b) {
        return a + b;
    }

    // インスタンスメソッド: オブジェクトに属する
    // → オブジェクトを作って呼ぶ
    // → インスタンス変数にアクセスできる
    void addToMemory(int value) {
        this.memory += value; // インスタンス変数を使用
    }

    int getMemory() {
        return memory;
    }
}

// staticメソッドの呼び出し（オブジェクト不要）
int result = Calculator.add(3, 5); // 8

// インスタンスメソッドの呼び出し（オブジェクト必要）
Calculator calc = new Calculator();
calc.addToMemory(10);
System.out.println(calc.getMemory()); // 10

