public class ScopeExample {
    static int classVar = 100; // クラス変数（どこからでも参照可能）

    static void method() {
        int localVar = 10; // ローカル変数（このメソッド内のみ）

        if (localVar > 5) {
            int blockVar = 20; // ブロック変数（if内のみ）
            System.out.println(localVar);  // OK
            System.out.println(blockVar);  // OK
        }
        // System.out.println(blockVar); // コンパイルエラー！

        for (int i = 0; i < 3; i++) {
            // i はこのforブロック内のみ有効
        }
        // System.out.println(i); // コンパイルエラー！
    }

    static void anotherMethod() {
        // System.out.println(localVar); // コンパイルエラー！
        System.out.println(classVar);     // OK
    }
}

// スコープの範囲:
// クラス変数 → クラス全体
// ローカル変数 → 宣言されたメソッド内
// ブロック変数 → 宣言されたブロック{} 内
// for変数 → forブロック内

// 階乗: n! = n × (n-1) × ... × 1
static int factorial(int n) {
    // ベースケース（終了条件）: 必ず必要！
    if (n <= 1) return 1;
    // 再帰呼び出し
    return n * factorial(n - 1);
}
// factorial(4) → 4 * factorial(3)
//              → 4 * 3 * factorial(2)
//              → 4 * 3 * 2 * factorial(1)
//              → 4 * 3 * 2 * 1 = 24

System.out.println(factorial(5)); // 120

// フィボナッチ数列: 0, 1, 1, 2, 3, 5, 8, 13, ...
static int fibonacci(int n) {
    if (n <= 0) return 0;
    if (n == 1) return 1;
    return fibonacci(n - 1) + fibonacci(n - 2);
}
System.out.println(fibonacci(7)); // 13

// ⚠️ ベースケースがないと無限ループ → StackOverflowError
// static int bad(int n) {
//     return n * bad(n - 1); // 終了条件なし！
// }

