// ❌ 悪い例: 1つのメソッドで多くのことをしている
// processメソッドの定義
static void process(String name, int age, String email) {
    // 条件分岐
    if (name != null && !name.isEmpty()) {
        if (age >= 0 && age <= 150) {
            if (email.contains("@")) {
                // 登録処理...
                System.out.println("登録完了");
            } else {
                System.out.println("メール不正");
            }
        } else {
            System.out.println("年齢不正");
        }
    } else {
        System.out.println("名前不正");
    }
}

// ✅ 良い例: 早期リターンでネストを浅く
// registerメソッドの定義
static void register(String name, int age, String email) {
    if (name == null || name.isEmpty()) {
        System.out.println("名前不正");
        return;
    }
    if (age < 0 || age > 150) {
        System.out.println("年齢不正");
        return;
    }
    if (!email.contains("@")) {
        System.out.println("メール不正");
        return;
    }
    // ここに来た時点で全バリデーション通過
    System.out.println("登録完了");
}

// ❌ 1つのメソッドに全部入り
// showReportメソッドの定義
static void showReport(int[] scores) {
    // 変数の宣言と初期化
    int sum = 0;
    // 拡張for文（コレクションの全要素を順番に処理）
    for (int s : scores) sum += s;
    double avg = (double) sum / scores.length;
    int max = Integer.MIN_VALUE;
    for (int s : scores) if (s > max) max = s;
    int min = Integer.MAX_VALUE;
    for (int s : scores) if (s < min) min = s;
    System.out.println("合計: " + sum);
    System.out.println("平均: " + avg);
    System.out.println("最高: " + max);
    System.out.println("最低: " + min);
}

// ✅ 責務ごとにメソッド分割
// calcSumメソッドの定義
static int calcSum(int[] scores) {
    int sum = 0;
    for (int s : scores) sum += s;
    return sum;
}
static double calcAverage(int[] scores) {
    return (double) calcSum(scores) / scores.length;
}
static int findMax(int[] scores) {
    int max = Integer.MIN_VALUE;
    for (int s : scores) if (s > max) max = s;
    return max;
}
static void showReport(int[] scores) {
    System.out.println("合計: " + calcSum(scores));
    System.out.println("平均: " + calcAverage(scores));
    System.out.println("最高: " + findMax(scores));
}

